template:
case class Config(port: Int, timeout: Int, mode: String, maxRetries: Option[Int])

def parseConfig(raw: Map[String, String]): Either[String, Config] = {
  for {
    portStr <- raw.get("port").toRight("Invalid port: missing")
    port <- portStr.[[SLOT to_int]].toRight("Invalid port: not an integer")
    _ <- [[SLOT cond_fn]](port >= 1 && port <= 65535, (), "Invalid port: out of range")

    timeoutStr <- raw.get("timeout").toRight("Invalid timeout: missing")
    timeout <- timeoutStr.toIntOption.toRight("Invalid timeout: not an integer")
    _ <- Either.cond(timeout > 0, (), "Invalid timeout: must be positive")

    modeStr <- raw.get("mode").toRight("Invalid mode: missing")
    mode <- Either.cond(
      [[SLOT mode_set]].contains(modeStr),
      modeStr,
      "Invalid mode: must be dev, staging, or prod"
    )

    maxRetries <- raw.get("maxRetries") match {
      case None => Right(None)
      case Some(str) => 
        str.toIntOption
          .toRight("Invalid maxRetries: not an integer")
          .[[SLOT chain_op]] { n =>
            Either.cond(n >= 0 && n <= 10, Some(n), "Invalid maxRetries: must be 0-10")
          }
    }
  } yield Config(port, timeout, mode, maxRetries)
}
